/**
 * Represents an image with optional source information and alternative text.
 */
export interface Image {
    /**
     * The source URL of the image. This property is optional and can be `null` if no image source is provided.
     */
    readonly src?: string | null;
    /**
     * An optional array of image sources for different resolutions, typically used for responsive images.
     * Can be `null` if no source set is provided.
     */
    readonly srcSet?: string[] | null;
    /**
     * The alternative text for the image, providing a textual description of the image's content.
     * This property is required.
     */
    readonly alt: string;
}
